const r=".overview{margin-top:.95rem;border-radius:22px;border:1px solid var(--border);background:radial-gradient(130% 220% at 8% -35%,rgba(255,122,24,.16),transparent 60%),radial-gradient(120% 170% at 102% 0,rgba(49,196,255,.18),transparent 62%),linear-gradient(180deg,#111826eb,#0c121ef2);box-shadow:var(--shadow-lg);padding:1rem}.overview-head{margin-bottom:.8rem}.overview-title{margin:0;font-size:1.05rem;font-weight:760;color:var(--text-1)}.overview-subtitle{margin:.38rem 0 0;color:var(--text-2);font-size:.85rem;line-height:1.4}.overview-grid{display:grid;gap:.68rem;grid-template-columns:repeat(2,minmax(0,1fr))}.overview-panel{border-radius:14px;border:1px solid var(--border-soft);background:#ffffff05;padding:.74rem}.overview-panel-title{margin:0;font-size:.72rem;letter-spacing:.08em;text-transform:uppercase;color:var(--text-3);font-weight:800}.overview-list{margin:.62rem 0 0;list-style:none;padding:0;display:grid;gap:.42rem}.overview-row{display:flex;align-items:center;justify-content:space-between;gap:.6rem;border-radius:11px;border:1px solid rgba(255,255,255,.08);background:#ffffff05;padding:.48rem .56rem}.overview-main{margin:0;font-size:.83rem;font-weight:700;color:var(--text-1)}.overview-meta{margin:.15rem 0 0;font-size:.72rem;color:var(--text-3)}.overview-quality{margin:0;flex:0 0 auto;border-radius:999px;border:1px solid var(--border-soft);background:#ffffff05;color:var(--text-2);font-size:.69rem;font-weight:700;padding:.24rem .5rem}.overview-quality-good{border-color:#10b9816b;color:#8af4c6;background:#10b9811f}.overview-quality-mid{border-color:#f59e0b73;color:#ffda9b;background:#f59e0b24}.overview-quality-low{border-color:#f871716b;color:#ffb0b0;background:#f871711f}@media(max-width:860px){.overview-grid{grid-template-columns:1fr}}@media(max-width:540px){.overview{padding:.84rem}.overview-row{align-items:flex-start;flex-direction:column}}";export{r as s};
